func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    m := len(grid)
    if m == 0 {
        return grid
    }
    n := len(grid[0])

    // Create a deep copy of the grid
    newGrid := make([][]int64, m)
    for i := 0; i < m; i++ {
        newGrid[i] = make([]int64, n)
        for j := 0; j < n; j++ {
            newGrid[i][j] = grid[i][j]
        }
    }

    xInt := int(x)
    yInt := int(y)
    kInt := int(k)

    // Collect the submatrix rows
    rowsInSubmatrix := make([][]int64, kInt)
    for i := 0; i < kInt; i++ {
        row := make([]int64, kInt)
        for j := 0; j < kInt; j++ {
            row[j] = newGrid[xInt+i][yInt+j]
        }
        rowsInSubmatrix[i] = row
    }

    // Reverse the rows
    for i := 0; i < kInt/2; i++ {
        rowsInSubmatrix[i], rowsInSubmatrix[kInt-1-i] = rowsInSubmatrix[kInt-1-i], rowsInSubmatrix[i]
    }

    // Put back the reversed rows into newGrid
    for i := 0; i < kInt; i++ {
        for j := 0; j < kInt; j++ {
            newGrid[xInt+i][yInt+j] = rowsInSubmatrix[i][j]
        }
    }

    return newGrid
}
