func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    m := len(grid)
    if m == 0 {
        return grid
    }
    n := len(grid[0])

    // Create a deep copy of the grid
    newGrid := make([][]int64, m)
    for i := 0; i < m; i++ {
        newGrid[i] = make([]int64, n)
        copy(newGrid[i], grid[i])
    }

    // Extract the rows to be reversed
    startRow := int(x)
    endRow := startRow + int(k) - 1
    rowsToReverse := newGrid[startRow : endRow+1]

    // Reverse the rows
    reversedRows := make([][]int64, len(rowsToReverse))
    for i := 0; i < len(rowsToReverse); i++ {
        reversedRows[i] = rowsToReverse[len(rowsToReverse)-1-i]
    }

    // Replace the rows in newGrid
    for i := 0; i < len(reversedRows); i++ {
        row := newGrid[startRow + i]
        for j := 0; j < k; j++ {
            row[y + j] = reversedRows[i][j]
        }
    }

    return newGrid
}
